{"command": "cd /app/data/auto-opt/utils/llvm-85265 && python $AGENT_TOOLS_DIR/apply_code.py write llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp 8793 8860 '  // Handle fcmp with fptrunc LHS and constant RHS:
  // fcmp pred (fptrunc Src X), Dst C -> fcmp pred Src X, threshold
  // where threshold is computed based on the predicate and C.
  // The threshold is the midpoint between C and the adjacent float value,
  // computed in the source type precision to avoid rounding issues.
  if (match(Op0, m_FPTrunc(m_Value(X)))) {
    const APFloat *C;
    if (match(Op1, m_APFloat(C)) && !C->isNaN() && !C->isInfinity()) {
      Type *SrcTy = X->getType()->getScalarType();
      const fltSemantics &SrcSem = SrcTy->getFltSemantics();
      const fltSemantics &DstSem = Op1->getType()->getScalarType()->getFltSemantics();

      // Compute threshold based on predicate.
      // For >= and <=, threshold is the midpoint between C and adjacent float.
      // For > and <, threshold is also the midpoint but with opposite direction.
      bool ComputeUpper = false; // true means we need the upper threshold

      switch (Pred) {
      default:
        break;
      case FCmpInst::FCMP_OGE:
      case FCmpInst::FCMP_UGE:
        // X >= C after trunc means X >= midpoint(prev_float(C), C)
        ComputeUpper = false;
        break;
      case FCmpInst::FCMP_OGT:
      case FCmpInst::FCMP_UGT:
        // X > C after trunc means X > midpoint(C, next_float(C))
        ComputeUpper = true;
        break;
      case FCmpInst::FCMP_OLE:
      case FCmpInst::FCMP_ULE:
        // X <= C after trunc means X <= midpoint(C, next_float(C))
        ComputeUpper = true;
        break;
      case FCmpInst::FCMP_OLT:
      case FCmpInst::FCMP_ULT:
        // X < C after trunc means X < midpoint(prev_float(C), C)
        ComputeUpper = false;
        break;
      }

      // Get the semantics we want (src or dst)
      const fltSemantics &WorkSem = SrcSem;

      // Convert C to source type first
      APFloat WorkC = *C;
      bool Lossy;
      WorkC.convert(WorkSem, APFloat::rmNearestTiesToEven, &Lossy);

      // Get the adjacent value in the source type that corresponds to 
      // the adjacent float value
      APFloat AdjC = WorkC;
      if (ComputeUpper) {
        // Get next value toward +inf in source type
        AdjC.next(/*nextDown=*/false);
      } else {
        // Get previous value toward -inf in source type  
        AdjC.next(/*nextDown=*/true);
      }

