      APFloat Threshold = WorkC;
      Threshold.add(AdjC, APFloat::rmNearestTiesToEven);
      Threshold.divide(APFloat(Threshold.getSemantics(), 2U),
                      APFloat::rmNearestTiesToEven);

      // Create the new constant in the source type
      Constant *NewC = ConstantFP::get(X->getType(), Threshold);

      return new FCmpInst(Pred, X, NewC, "", &I);
    }
